import React, { useState } from 'react';
import './AddPurchase.css';


const AddPurchase = ({ handleAdd }) => {

  const initialPurchaseState = {
    location: '', // Initialize location to an empty string
    materialid: '',
    quantity: '',
    price: '',
    vendor: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);


  

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase({
      ...newPurchase,
      [name]: value,
    });
  };

  

  const handleSubmit = (e) => {
    e.preventDefault();
    handleAdd(newPurchase);
    setNewPurchase(initialPurchaseState); // Clear the form after adding a purchase
  };


  const resetForm = () => {
    setNewPurchase({
        id: '',
        location: '',
        materialid: '',
        quantity: '',
        price:'',
        vendor:'',
    });
  };

  

  
  
  return (
    <div className="add-purchase-container">
      <h2 className="add-purchase-heading">Add Purchase</h2>
      <form className="add-purchase-form" onSubmit={handleSubmit}>
        <div className="form-row">          
          <div className="form-group">
          <label>Location:</label>
            <select name="location" value={newPurchase.location} onChange={handleChange}>
              <option value="">Select a location</option>
              {locations.map((location) => (
                <option key={location.id} value={location.id}>
                  {location.locationname}
                </option>
              ))}
            </select>
              </div>
          <div className="form-group">
            <label htmlFor="materialid">Material ID:</label>
            <input
              type="text" 
              id="materialid"
              name="materialid"
              value={newPurchase.materialid}
              onChange={handleInputChange}
              required
            />
          </div>
          
          <div className="form-group">
            <label htmlFor="quantity">Quantity:</label>
            <input
              type="text"
              id="quantity"
              name="quantity"
              value={newPurchase.quantity}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="price">Price:</label>
            <input
              type="number" 
              id="price"
              name="price"
              value={newPurchase.price}
              onChange={handleInputChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="vendor">Vendor:</label>
            <input
              type="number"
              id="vendor"
              name="vendor"
              value={newPurchase.vendor}
              onChange={handleInputChange}
              required
            />
          </div>
          
        
        </div>
        <button type="submit" className="add-purchase-btn">
          Add
        </button>
      </form>
    </div>
  );
};

export default AddPurchase;
